import React, { Component } from 'react';
import { styled, createTheme, ThemeProvider } from '@mui/material/styles';
import {
  CssBaseline,
  Box,
  AppBar as MuiAppBar,
  Toolbar,
  Link,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Button,
  TextField
} from '@mui/material';

const AppBar = styled(MuiAppBar)(({ theme }) => ({
  zIndex: theme.zIndex.drawer + 1,
  backgroundColor: '#333',
  boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
}));

const defaultTheme = createTheme();

export default class Dashboard extends Component {
  constructor(props) {
    super(props);
    this.state = {
      isNightMode: false,
      name: '',
      email: '',
      message: '',
    };
  }

  toggleTheme = () => {
    this.setState((prevState) => ({
      isNightMode: !prevState.isNightMode,
    }));
  };

  handleChange = (e) => {
    this.setState({ [e.target.name]: e.target.value });
  };

  handleSubmit = (e) => {
    e.preventDefault();
    // Handle form submission logic here
    console.log('Form submitted:', this.state);
  };
  render() {
    const { isNightMode, name, email, message } = this.state;

    const projects = [
      {
        title: 'Project 1',
        description: 'Description of project 1.',
        link: 'https://github.com/yourusername/project1',
      },
      {
        title: 'Project 2',
        description: 'Description of project 2.',
        link: 'https://github.com/yourusername/project2',
      },
      // Add more projects as needed
    ];

    return (
      <ThemeProvider theme={defaultTheme}>
        <CssBaseline />
        <Box
          sx={{
            display: 'flex',
            flexDirection: 'column',
            height: '100vh',
            backgroundColor: isNightMode ? '#333' : '#fff',
            color: isNightMode ? '#fff' : '#000',
            paddingBottom: 3,
          }}
        >
          <AppBar position="absolute">
            <Toolbar component="nav" variant="dense" sx={{ justifyContent: 'space-between', overflowX: 'auto' }}>
              <h1 style={{ fontSize: '24px', fontWeight: 'bold', color: '#fff' }}>Logo</h1>
              {[
                { title: "About", url: "#about" },
                { title: "Skills", url: "#skills" },
                { title: "Experience", url: "#experience" },
                { title: "Projects", url: "#projects" },
                { title: "Education", url: "#education" },
                { title: "Contact", url: "#contact" }
              ].map((section) => (
                <Link
                  color="inherit"
                  noWrap
                  key={section.title}
                  variant="body2"
                  href={section.url}
                  sx={{ p: 1, flexShrink: 0, fontSize: '16px', textDecoration: 'none' }}
                >
                  {section.title}
                </Link>
              ))}
              <Button onClick={this.toggleTheme} variant="contained" color="primary" sx={{ marginLeft: 2 }}>
                {isNightMode ? 'Switch to Day Mode' : 'Switch to Night Mode'}
              </Button>
            </Toolbar>
          </AppBar>

          <Box component="main" sx={{ flexGrow: 1, overflow: 'auto', padding: 2 }}>
            <Container id="home" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h2" gutterBottom sx={{ fontWeight: 'bold', textAlign: 'center' }}>
                Welcome to My Portfolio
              </Typography>
              <Typography variant="h5" sx={{ textAlign: 'center' }}>
                I am a passionate web developer.
              </Typography>
            </Container>

            <Container id="about" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                About Me
              </Typography>
              <Typography variant="body1">
                I am a passionate web developer with experience in building dynamic and responsive web applications.
                I love coding and enjoy learning new technologies.
              </Typography>
            </Container>

            <Container id="projects" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Projects
              </Typography>
              <Grid container spacing={2}>
                {projects.map((project, index) => (
                  <Grid item xs={12} sm={6} md={4} key={index}>
                    <Card sx={{ boxShadow: 3, borderRadius: 2 }}>
                      <CardContent>
                        <Typography variant="h5" sx={{ fontWeight: 'bold' }}>{project.title}</Typography>
                        <Typography variant="body2">{project.description}</Typography>
                        <Button
                          href={project.link}
                          target="_blank"
                          variant="contained"
                          color="primary"
                          sx={{ marginTop: 2, backgroundColor: '#1976d2', '&:hover': { backgroundColor: '#1565c0' } }}
                        >
                          View Project
                        </Button>
                      </CardContent>
                    </Card>
                  </Grid>
                ))}
              </Grid>
            </Container>

            <Container id="skills" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Skills
              </Typography>
              <Typography variant="body1">
                JavaScript, React, Node.js, HTML, CSS, etc.
              </Typography>
            </Container>

            <Container id="experience" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Experience
              </Typography>
              <Typography variant="body1">
                Previous work experience or internships can be listed here.
              </Typography>
            </Container>

            <Container id="education" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Education
              </Typography>
              <Typography variant="body1">
                Your academic background can be listed here.
              </Typography>
            </Container>

            <Container id="contact" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Contact Me
              </Typography>
              <form onSubmit={this.handleSubmit} sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
                <TextField
                  label="Name"
                  name="name"
                  value={name}
                  onChange={this.handleChange}
                  fullWidth
                  required
                  sx={{ mb: 2, borderRadius: 1 }}
                />
                <TextField
                  label="Email"
                  name="email"
                  type="email"
                  value={email}
                  onChange={this.handleChange}
                  fullWidth
                  required
                  sx={{ mb: 2, borderRadius: 1 }}
                />
                <TextField
                  label="Message"
                  name="message"
                  value={message}
                  onChange={this.handleChange}
                  multiline
                  rows={4}
                  fullWidth
                  required
                  sx={{ mb: 2, borderRadius: 1 }}
                />
                <Button type="submit" variant="contained" color="primary" sx={{ backgroundColor: '#1976d2', '&:hover': { backgroundColor: '#1565c0' } }}>
                  Send Message
                </Button>
              </form>
            </Container>
          </Box>
        </Box>
      </ThemeProvider>
    );
  }
}
